class TreeNode:
    def __init__(self, val=0, left=None, right=None):
        self.val = val
        self.left = left
        self.right = right

def morris_inorder_traversal(root: TreeNode) -> list:
    result = []
    current = root

    while current is not None:
        if current.left is None:
            result.append(current.val)
            current = current.right
        else:
            # Find the inorder predecessor of current
            predecessor = current.left
            while predecessor.right is not None and predecessor.right is not current:
                predecessor = predecessor.right

            # If predecessor.right is None, it means we haven't visited
            # the left subtree yet. Make a link.
            if predecessor.right is None:
                predecessor.right = current
                current = current.left
            # If predecessor.right is current, it means we have visited
            # the left subtree and are returning. Break the link.
            else:
                predecessor.right = None  # Restore the tree
                result.append(current.val)
                current = current.right
    return result
